    private void launchFilePickerIntent(@Nullable FileChooserParams params) {
        Intent intent;
        if (params != null) {
            intent = params.createIntent();
        } else {
            intent = new Intent(Intent.ACTION_GET_CONTENT);
            intent.addCategory(Intent.CATEGORY_OPENABLE);
            intent.setType("*/*");
            intent.putExtra(Intent.EXTRA_ALLOW_MULTIPLE, true);
        }
        try {
            activityLauncher.launch(Intent.createChooser(intent, "Select file"));
        } catch (ActivityNotFoundException e) {
            if (filePathCallback != null) {
                filePathCallback.onReceiveValue(null);
                filePathCallback = null;
            }
            pendingAction = PendingAction.NONE;
        }
    }

    private void launchCameraIntent() {
        Intent takePicture = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
        if (takePicture.resolveActivity(getPackageManager()) == null) {
            if (filePathCallback != null) {
                filePathCallback.onReceiveValue(null);
                filePathCallback = null;
            }
            pendingAction = PendingAction.NONE;
            return;
        }

        try {
            File imageFile = createTempImageFile(this);
            cameraImageUri = FileProvider.getUriForFile(this, getPackageName() + ".fileprovider", imageFile);
            takePicture.putExtra(MediaStore.EXTRA_OUTPUT, cameraImageUri);
            takePicture.addFlags(Intent.FLAG_GRANT_WRITE_URI_PERMISSION | Intent.FLAG_GRANT_READ_URI_PERMISSION);
            activityLauncher.launch(takePicture);
        } catch (IOException e) {
            Log.e(TAG, "Failed to create image file", e);
            if (filePathCallback != null) {
                filePathCallback.onReceiveValue(null);
                filePathCallback = null;
            }
            pendingAction = PendingAction.NONE;
        }
    }

    private static File createTempImageFile(Context context) throws IOException {
        File dir = context.getExternalFilesDir(Environment.DIRECTORY_PICTURES);
        if (dir == null) dir = context.getFilesDir();
        if (!dir.exists()) dir.mkdirs();
        return File.createTempFile("cam_" + UUID.randomUUID(), ".jpg", dir);
    }

    public static class NativeBridge {
        private final Activity activity;
        private final WebView webView;
        private final FusedLocationProviderClient fusedLocationClient;

        private GeolocationPermissions.Callback pendingGeoCallback;
        private String pendingGeoOrigin;

        private PermissionRequest pendingWebPermissionRequest;

        NativeBridge(Activity activity, WebView webView, FusedLocationProviderClient fusedLocationClient) {
            this.activity = activity;
            this.webView = webView;
            this.fusedLocationClient = fusedLocationClient;
        }

        void setPendingGeoPrompt(String origin, GeolocationPermissions.Callback callback) {
            this.pendingGeoOrigin = origin;
            this.pendingGeoCallback = callback;
        }

        void setPendingWebPermissionRequest(PermissionRequest request) {
            this.pendingWebPermissionRequest = request;
        }

        void handlePermissionResult(boolean allGranted) {
            if (pendingGeoCallback != null) {
                pendingGeoCallback.invoke(pendingGeoOrigin, allGranted, false);
                pendingGeoCallback = null;
                pendingGeoOrigin = null;
            }

            if (pendingWebPermissionRequest != null) {
                if (allGranted) pendingWebPermissionRequest.grant(pendingWebPermissionRequest.getResources());
                else pendingWebPermissionRequest.deny();
                pendingWebPermissionRequest = null;
            }
        }

        private void postResult(String callbackId, JSONObject payload) {
            if (callbackId == null) return;
            final String js = "window.NativeBridge && NativeBridge._resolve && NativeBridge._resolve(" +
                    JSONObject.quote(callbackId) + "," + payload.toString() + ");";
            activity.runOnUiThread(() -> {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.KITKAT) {
                    webView.evaluateJavascript(js, null);
                } else {
                    webView.loadUrl("javascript:" + js);
                }
            });
        }

        private void postError(String callbackId, String code, String message) {
            try {
                JSONObject payload = new JSONObject();
                payload.put("ok", false);
                payload.put("code", code);
                payload.put("message", message);
                postResult(callbackId, payload);
            } catch (JSONException ignored) {}
        }

        private void postOk(String callbackId, JSONObject data) {
            try {
                JSONObject payload = new JSONObject();
                payload.put("ok", true);
                payload.put("data", data != null ? data : new JSONObject());
                postResult(callbackId, payload);
            } catch (JSONException ignored) {}
        }

        @JavascriptInterface
        public String getPlatform() {
            return "android";
        }

        @JavascriptInterface
        public String getAppVersion() {
            try {
                return activity.getPackageManager().getPackageInfo(activity.getPackageName(), 0).versionName;
            } catch (Exception e) {
                return "";
            }
        }

        @JavascriptInterface
        public void openExternalUrl(String url) {
            try {
                Intent i = new Intent(Intent.ACTION_VIEW, Uri.parse(url));
                activity.startActivity(i);
            } catch (Exception e) {
                Log.w(TAG, "openExternalUrl failed: " + e.getMessage());
            }
        }

        @JavascriptInterface
        public void requestLocation(String callbackId) {
            if (ContextCompat.checkSelfPermission(activity, Manifest.permission.ACCESS_FINE_LOCATION) != PackageManager.PERMISSION_GRANTED) {
                postError(callbackId, "PERMISSION_DENIED", "Location permission not granted");
                return;
            }

            try {
                fusedLocationClient.getLastLocation()
                        .addOnSuccessListener(activity, location -> {
                            if (location == null) {
                                postError(callbackId, "NO_LOCATION", "Location unavailable");
                                return;
                            }
                            try {
                                JSONObject data = new JSONObject();
                                data.put("latitude", location.getLatitude());
                                data.put("longitude", location.getLongitude());
                                data.put("accuracy", location.getAccuracy());
                                data.put("time", location.getTime());
                                postOk(callbackId, data);
                            } catch (JSONException e) {
                                postError(callbackId, "JSON_ERROR", e.getMessage());
                            }
                        })
                        .addOnFailureListener(activity, e -> postError(callbackId, "LOCATION_ERROR", e.getMessage()));
            } catch (Exception e) {
                postError(callbackId, "LOCATION_ERROR", e.getMessage());
            }
        }

        @JavascriptInterface
        public void openCamera(String callbackId) {
            // MVP: delegate to WebView file chooser; provide a direct camera intent for native call
            if (ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA) != PackageManager.PERMISSION_GRANTED) {
                postError(callbackId, "PERMISSION_DENIED", "Camera permission not granted");
                return;
            }
            Intent takePicture = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
            if (takePicture.resolveActivity(activity.getPackageManager()) == null) {
                postError(callbackId, "NO_CAMERA_APP", "No camera app available");
                return;
            }
            postError(callbackId, "UNSUPPORTED", "Use <input type=\"file\" accept=\"image/*\" capture> for MVP");
        }

        @JavascriptInterface
        public void pay(String json, String callbackId) {
            // MVP stub: integrate Play Billing/SDK later; for now echo back
            try {
                JSONObject req = json != null && !json.isEmpty() ? new JSONObject(json) : new JSONObject();
                JSONObject data = new JSONObject();
                data.put("status", "stub");
                data.put("request", req);
                data.put("message", "Payment not integrated in MVP");
                postOk(callbackId, data);
            } catch (JSONException e) {
                postError(callbackId, "JSON_ERROR", e.getMessage());
            }
        }

        @JavascriptInterface
        public void log(String message) {
            Log.d(TAG, "JS: " + message);
        }

        @JavascriptInterface
        public void injectBridgeHelpers() {
            final String js =
                    "(function(){" +
                            "if(window.NativeBridge && window.NativeBridge._resolve) return;" +
                            "window.NativeBridge = window.NativeBridge || {};" +
                            "var _cbs = {};" +
                            "NativeBridge._resolve = function(id, payload){ try{ if(_cbs[id]){ _cbs[id](payload); delete _cbs[id]; } }catch(e){} };" +
                            "NativeBridge._call = function(method, args){" +
                            "  args = args || {};" +
                            "  return new Promise(function(resolve){" +
                            "    var id = String(Date.now()) + '_' + Math.random().toString(16).slice(2);" +
                            "    _cbs[id] = resolve;" +
                            "    try{ " +
                            "      if(typeof args === 'object' && args !== null){" +
                            "        " + JS_BRIDGE_NAME + "[method](JSON.stringify(args), id);" +
                            "      } else {" +
                            "        " + JS_BRIDGE_NAME + "[method](String(args||''), id);" +
                            "      }" +
                            "    }catch(e){ resolve({ok:false, code:'BRIDGE_ERROR', message:String(e)}); }" +
                            "  });" +
                            "};" +
                            "NativeBridge.requestLocation = function(){ return NativeBridge._call('requestLocation', {}); };" +
                            "NativeBridge.pay = function(req){ return NativeBridge._call('pay', req||{}); };" +
                            "})();";
            activity.runOnUiThread(() -> {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.KITKAT) {
                    webView.evaluateJavascript(js, null);
                } else {
                    webView.loadUrl("javascript:" + js);
                }
            });
        }

        // Overloads so helper can call methods uniformly
        @JavascriptInterface
        public void requestLocation(String jsonArgs, String callbackId) {
            requestLocation(callbackId);
        }

        @JavascriptInterface
        public void pay(String jsonArgs, String callbackId, String unused) {
            pay(jsonArgs, callbackId);
        }
    }
